"use client";

import { useEffect, useState } from "react";
import { Heart, Share2, MessageCircle, Bookmark } from "lucide-react";
import { cn } from "@/lib/utils";
import { CountUp } from "./count-up";

const METRICS = [
  { key: "likes", label: "Likes", icon: Heart, start: 124, end: 892 },
  { key: "shares", label: "Shares", icon: Share2, start: 12, end: 146 },
  { key: "comments", label: "Comments", icon: MessageCircle, start: 4, end: 63 },
  { key: "saves", label: "Saves", icon: Bookmark, start: 8, end: 94 },
] as const;

export function EngagementCard({ className }: { className?: string }) {
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    const prefersReduced = typeof window !== "undefined" && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReduced) {
      setMounted(true);
      return;
    }
    const t = setTimeout(() => setMounted(true), 100);
    return () => clearTimeout(t);
  }, []);

  return (
    <article
      className={cn(
        "w-full max-w-sm rounded-2xl border border-[var(--canvas-border)] bg-[var(--canvas-surface)] p-4 shadow-lg transition-all duration-300 ease-out hover:shadow-xl hover:-translate-y-0.5",
        "opacity-0 translate-y-3 transition-all duration-500 ease-out",
        mounted && "opacity-100 translate-y-0",
        className
      )}
      aria-label="Social engagement preview"
    >
      {/* Badge */}
      <div className="mb-3 flex items-center justify-center">
        <span className="rounded-full bg-[var(--canvas-accent-mint)] px-3 py-1 text-xs font-medium text-[var(--canvas-heading)]">
          Engagement rising
        </span>
      </div>

      {/* Meme preview area */}
      <div className="overflow-hidden rounded-xl border border-[var(--canvas-border)] bg-stone-50">
        <div className="aspect-[4/3] flex flex-col items-center justify-center p-4 text-center">
          <p className="text-sm font-medium text-[var(--canvas-heading)] leading-snug">
            When the brief says
            <br />
            &ldquo;make it pop&rdquo;
          </p>
          <p className="mt-1 text-xs text-[var(--canvas-muted)]">
            — and you actually do
          </p>
        </div>
      </div>

      {/* Caption */}
      <p className="mt-2 text-xs text-[var(--canvas-muted)] line-clamp-2">
        On-brand meme, ready for social. Reach and engagement in one asset.
      </p>

      {/* Metrics row */}
      <div className="mt-4 flex items-center justify-between gap-2 border-t border-[var(--canvas-border)] pt-3">
        {METRICS.map(({ key, label, icon: Icon, start, end }) => (
          <div
            key={key}
            className="flex flex-col items-center gap-0.5 min-w-0 flex-1"
          >
            <Icon
              className="h-4 w-4 shrink-0 text-[var(--canvas-muted)]"
              aria-hidden
            />
            <CountUp
              end={end}
              start={start}
              duration={2000}
              className="text-sm font-semibold tabular-nums text-[var(--canvas-heading)]"
            />
            <span className="sr-only">{label}</span>
          </div>
        ))}
      </div>
    </article>
  );
}
